import { useCallback } from 'react';
import { addToast } from '@linm-soft/common-components';
import type { AppDispatch } from '../../../../../store/store';
import { serializeVoucherSnapshot } from '../../../../../components/voucher';
import type { CashVoucherKind } from '../../../../../components/kt/CashVoucherList';
import { getApiErrorMessage } from '../../../../../utils/getApiErrorMessage';
import type { CashVoucherConfig } from '../config/cashVoucherConfig';
import { buildSnapshotFromState, mapFormStateToPayload } from '../mappers/cashVoucherMappers';
import type { CashVoucherFormAction, CashVoucherFormReducerState } from '../types/cashVoucherFormState.types';

export function useCashVoucherSubmit(params: {
  kind: CashVoucherKind;
  cfg: CashVoucherConfig;
  state: CashVoucherFormReducerState;
  dispatch: React.Dispatch<CashVoucherFormAction>;
  isNew: boolean;
  id?: string;
  showInvoiceGrid: boolean;
  totalAmount: number;
  listPath: string;
  saveSuccessLabel: string;
  navigate: (path: string) => void;
  appDispatch: AppDispatch;
  onSaveSuccessNew: (createdId: string, code: string) => void;
  onSaveSuccessUpdate: () => void;
}) {
  const {
    kind, cfg, state, dispatch, isNew, id, showInvoiceGrid, totalAmount,
    listPath, saveSuccessLabel, navigate, appDispatch, onSaveSuccessNew, onSaveSuccessUpdate,
  } = params;

  const save = useCallback(async () => {
    const payload = mapFormStateToPayload(state, cfg, kind, { showInvoiceGrid, totalAmount });
    if (isNew) {
      const created = await cfg.create(payload);
      dispatch({ type: 'SET_HEADER', key: 'voucherNumber', value: created.code });
      appDispatch(addToast({ message: saveSuccessLabel, type: 'success' }));
      const snap = serializeVoucherSnapshot(
        buildSnapshotFromState(state, { showInvoiceGrid }),
      );
      dispatch({ type: 'SET_META', patch: { savedSnapshot: snap } });
      dispatch({ type: 'COMMIT_INITIAL' });
      onSaveSuccessNew(created.id, created.code);
      navigate(`${listPath}/${created.id}`);
    } else {
      await cfg.update(id!, payload);
      appDispatch(addToast({ message: 'Cập nhật thành công', type: 'success' }));
      const snap = serializeVoucherSnapshot(
        buildSnapshotFromState(state, { showInvoiceGrid }),
      );
      dispatch({ type: 'SET_META', patch: { savedSnapshot: snap } });
      dispatch({ type: 'COMMIT_INITIAL' });
      onSaveSuccessUpdate();
    }
  }, [
    state, cfg, kind, showInvoiceGrid, totalAmount, isNew, id,
    saveSuccessLabel, navigate, appDispatch, onSaveSuccessNew, onSaveSuccessUpdate, dispatch,
  ]);

  const saveWithErrorToast = useCallback(async () => {
    try {
      await save();
    } catch (e: unknown) {
      appDispatch(addToast({
        message: getApiErrorMessage(e, 'Lưu thất bại. Vui lòng thử lại.'),
        type: 'error',
      }));
    }
  }, [save, appDispatch]);

  return { save, saveWithErrorToast };
}
