import React, { useState } from 'react';
import { Button, Input, Select } from '@linm-soft/common-components';
import { CustomerSearchField, AccountSearchInput, ContractSearchField } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import { VoucherDescriptionField } from '../../../../../components/voucher';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import styles from '../../../../../styles/documentForm.module.css';

export const CashVoucherHeaderSection: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const {
    kind,
    labels,
    receiptKind,
    setReceiptKind,
    receiptKindOpts,
    receiptKindLocked,
    tid,
    viewSectionClass,
    voucherDate,
    setVoucherDate,
    fieldErrors,
    patchHeaderFieldError,
    fieldLockProps,
    voucherNumber,
    ph,
    staticFieldProps,
    currencyLabel,
    exchangeRate,
    showHeaderCustomer,
    customerId,
    customerCode,
    customerName,
    representativeName,
    setCustomerId,
    setCustomerCode,
    setCustomerName,
    setRepresentativeName,
    customerPhone,
    setCustomerPhone,
    searchFieldClass,
    searchDisabled,
    reference,
    referenceCustomerName,
    setReference,
    setReferenceCustomerName,
    showAllocateBtn,
    setShowAllocateModal,
    isReadOnly,
    accountCode,
    accountName,
    setAccountCode,
    setAccountName,
    showCounterAccountHeader,
    counterAccountCode,
    counterAccountName,
    setCounterAccountCode,
    setCounterAccountName,
    description,
    setDescription,
    textareaClassName,
    textareaReadOnly,
    textareaDisabled,
    selectDisabled,
  } = vm;

  const useCompactHeader = kind === 'receipt';
  /** Mặc định full mọi mode — user «Thu gọn» nếu cần §8.10.3 */
  const [headerExpanded, setHeaderExpanded] = useState(true);

  const customerField = showHeaderCustomer ? (
    <div
      id={tid('field-customerId')}
      className={`${styles.field} ${styles.spanCol2}`}
      data-testid={tid('field-customerId')}
    >
      <label className={styles.label}>{labels.partnerLabel}</label>
      <CustomerSearchField
        testIdPrefix={tid('customer')}
        className={searchFieldClass}
        customerId={customerId}
        customerCode={customerCode}
        customerName={customerName}
        onSelect={c => {
          setCustomerId(c.customerId);
          setCustomerCode(c.code);
          setCustomerName(c.name);
          setRepresentativeName(c.name);
          setCustomerPhone(c.phone ?? '');
        }}
        onClear={() => {
          setCustomerId('');
          setCustomerCode('');
          setCustomerName('');
          setCustomerPhone('');
        }}
        placeholder={ph('Nhập mã hoặc tên đối tượng...')}
        disabled={searchDisabled}
      />
    </div>
  ) : null;

  const accountField = (
    <div
      id={tid('field-accountCode')}
      className={styles.field}
      data-testid={tid('field-accountCode')}
    >
      <label className={styles.label}>{labels.cashLabel} *</label>
      <AccountSearchInput
        api={erpFinanceAccountSearchApi}
        className={searchFieldClass}
        value={accountCode}
        primaryDisplay={formatAccountDisplay(accountCode, accountName)}
        error={fieldErrors.accountCode}
        onChange={a => {
          setAccountCode(a.code);
          setAccountName(a.name);
          patchHeaderFieldError('accountCode', a.code);
        }}
        onClear={() => {
          setAccountCode('');
          setAccountName('');
          patchHeaderFieldError('accountCode', '');
        }}
        showLabel={false}
        showSecondaryInput={false}
        placeholder={ph('Mã hoặc tên TK...')}
        disabled={searchDisabled}
      />
    </div>
  );

  const receiptKindField = kind === 'receipt' ? (
    <div className={styles.field}>
      <label className={styles.label}>{labels.receiptKind}</label>
      <Select
        data-testid={tid('field-receiptKind')}
        options={receiptKindOpts}
        value={receiptKind}
        onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setReceiptKind(e.target.value)}
        disabled={selectDisabled || receiptKindLocked}
      />
    </div>
  ) : null;

  const voucherDateField = (
    <div
      id={tid('field-voucherDate')}
      className={styles.field}
      data-testid={tid('field-voucherDate')}
    >
      <label className={styles.label}>{labels.voucherDate} *</label>
      <Input
        type="date"
        value={voucherDate}
        error={fieldErrors.voucherDate}
        onChange={e => {
          const v = e.target.value;
          setVoucherDate(v);
          patchHeaderFieldError('voucherDate', v);
        }}
        {...fieldLockProps}
      />
    </div>
  );

  const headerToggle = useCompactHeader ? (
    <button
      type="button"
      className={styles.headerToggleBtn}
      data-testid={tid(headerExpanded ? 'header-collapse' : 'header-expand')}
      aria-expanded={headerExpanded}
      onClick={() => setHeaderExpanded(v => !v)}
    >
      <span className={styles.headerToggleIcon} aria-hidden>
        <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
      </span>
      {headerExpanded ? labels.headerCollapse : labels.headerExpand}
    </button>
  ) : null;

  const expandedOnlyFields = (
    <>
      <div className={styles.row4}>
        <div className={styles.field}>
          <label className={styles.label}>{labels.voucherCode}</label>
          <Input value={voucherNumber} placeholder={ph('Tự động sinh')} {...staticFieldProps} />
        </div>
        <div className={styles.field}>
          <label className={styles.label}>{labels.currency}</label>
          <Input value={currencyLabel} {...staticFieldProps} />
        </div>
        <div className={styles.field}>
          <label className={styles.label}>{labels.exchangeRate}</label>
          <Input type="number" value={exchangeRate} {...staticFieldProps} />
        </div>
      </div>

      <div className={styles.row4}>
        <div className={styles.field} data-testid={tid('field-customerPhone')}>
          <label className={styles.label}>{labels.customerPhone}</label>
          <Input
            value={customerPhone}
            onChange={e => setCustomerPhone(e.target.value)}
            {...fieldLockProps}
          />
        </div>
        {showHeaderCustomer && (
          <div className={styles.field} data-testid={tid('field-representativeName')}>
            <label className={styles.label}>{labels.representativeLabel}</label>
            <Input
              value={representativeName}
              onChange={e => setRepresentativeName(e.target.value)}
              {...fieldLockProps}
            />
          </div>
        )}
        <div className={styles.field}>
          <label className={styles.label}>{labels.reference}{receiptKind === '1' ? ' *' : ''}</label>
          <ContractSearchField
            className={searchFieldClass}
            contractCode={reference}
            customerName={referenceCustomerName}
            onSelect={(code, name) => { setReference(code); setReferenceCustomerName(name); }}
            onClear={() => { setReference(''); setReferenceCustomerName(''); }}
            disabled={searchDisabled}
            placeholder={ph('Nhập mã hợp đồng...')}
          />
        </div>
      </div>

      {showAllocateBtn && (
        <div className={styles.row4}>
          <div className={styles.field}>
            <Button
              variant="secondary"
              type="button"
              data-testid={tid('allocate-invoices-btn')}
              onClick={() => setShowAllocateModal(true)}
              disabled={isReadOnly}
            >
              {labels.allocateInvoices}
            </Button>
          </div>
        </div>
      )}

      {showCounterAccountHeader ? (
        <>
          <div className={styles.row4}>
            <div
              className={`${styles.field} ${styles.spanCol2}`}
              data-testid={tid('field-counterAccountCode')}
            >
              <label className={styles.label}>{labels.lineThAccount} *</label>
              <AccountSearchInput
                api={erpFinanceAccountSearchApi}
                className={searchFieldClass}
                value={counterAccountCode}
                primaryDisplay={formatAccountDisplay(counterAccountCode, counterAccountName)}
                onChange={a => {
                  setCounterAccountCode(a.code);
                  setCounterAccountName(a.name);
                }}
                onClear={() => {
                  setCounterAccountCode('');
                  setCounterAccountName('');
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder={ph('TK đối ứng...')}
                disabled={searchDisabled}
              />
            </div>
          </div>
          <div className={styles.row4}>
            <div
              id={tid('field-description')}
              className={`${styles.field} ${styles.spanCol4}`}
              data-testid={tid('field-description')}
            >
              <label className={styles.label}>{labels.description}</label>
              <VoucherDescriptionField
                data-testid={tid('field-description-input')}
                value={description}
                error={fieldErrors.description}
                placeholder={ph('Nhập diễn giải...')}
                className={textareaClassName}
                onChange={v => {
                  setDescription(v);
                  patchHeaderFieldError('description', v);
                }}
                readOnly={textareaReadOnly}
                disabled={textareaDisabled}
              />
            </div>
          </div>
        </>
      ) : (
        <div className={styles.row4}>
          <div
            id={tid('field-description')}
            className={`${styles.field} ${styles.spanCol4}`}
            data-testid={tid('field-description')}
          >
            <label className={styles.label}>{labels.description}</label>
            <VoucherDescriptionField
              data-testid={tid('field-description-input')}
              value={description}
              error={fieldErrors.description}
              placeholder={ph('Nhập diễn giải...')}
              className={textareaClassName}
              onChange={v => {
                setDescription(v);
                patchHeaderFieldError('description', v);
              }}
              readOnly={textareaReadOnly}
              disabled={textareaDisabled}
            />
          </div>
        </div>
      )}
    </>
  );

  return (
    <div
      className={[styles.section, viewSectionClass].filter(Boolean).join(' ')}
      id={tid('section-header')}
      data-testid={tid('section-header')}
    >
      <div className={styles.sectionTitleRow}>
        <h2 className={styles.sectionTitle}>{labels.sectionHeader}</h2>
        {headerToggle}
      </div>

      {useCompactHeader ? (
        <>
          <div className={styles.row4}>
            {receiptKindField}
            {voucherDateField}
          </div>
          <div className={styles.row4}>
            {customerField}
            {accountField}
          </div>
          <div
            className={[
              styles.headerExpandCollapse,
              headerExpanded && styles.headerExpandCollapseOpen,
            ].filter(Boolean).join(' ')}
            data-testid={tid('header-expand-panel')}
            aria-hidden={!headerExpanded}
          >
            <div className={styles.headerExpandInner}>
              {expandedOnlyFields}
            </div>
          </div>
        </>
      ) : (
        <>
          <div className={styles.row4}>
            {voucherDateField}
            <div className={styles.field}>
              <label className={styles.label}>{labels.voucherCode}</label>
              <Input value={voucherNumber} placeholder={ph('Tự động sinh')} {...staticFieldProps} />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>{labels.currency}</label>
              <Input value={currencyLabel} {...staticFieldProps} />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>{labels.exchangeRate}</label>
              <Input type="number" value={exchangeRate} {...staticFieldProps} />
            </div>
          </div>

          <div className={styles.row4}>
            {customerField}
            <div className={styles.field} data-testid={tid('field-customerPhone')}>
              <label className={styles.label}>{labels.customerPhone}</label>
              <Input
                value={customerPhone}
                onChange={e => setCustomerPhone(e.target.value)}
                {...fieldLockProps}
              />
            </div>
            {showHeaderCustomer && (
              <div className={styles.field} data-testid={tid('field-representativeName')}>
                <label className={styles.label}>{labels.representativeLabel}</label>
                <Input
                  value={representativeName}
                  onChange={e => setRepresentativeName(e.target.value)}
                  {...fieldLockProps}
                />
              </div>
            )}
            <div className={styles.field}>
              <label className={styles.label}>{labels.reference}{receiptKind === '1' ? ' *' : ''}</label>
              <ContractSearchField
                className={searchFieldClass}
                contractCode={reference}
                customerName={referenceCustomerName}
                onSelect={(code, name) => { setReference(code); setReferenceCustomerName(name); }}
                onClear={() => { setReference(''); setReferenceCustomerName(''); }}
                disabled={searchDisabled}
                placeholder={ph('Nhập mã hợp đồng...')}
              />
            </div>
          </div>

          {showAllocateBtn && (
            <div className={styles.row4}>
              <div className={styles.field}>
                <Button
                  variant="secondary"
                  type="button"
                  data-testid={tid('allocate-invoices-btn')}
                  onClick={() => setShowAllocateModal(true)}
                  disabled={isReadOnly}
                >
                  {labels.allocateInvoices}
                </Button>
              </div>
            </div>
          )}

          <div className={styles.row4}>
            {accountField}
            {showCounterAccountHeader && (
              <div
                className={`${styles.field} ${styles.spanCol2}`}
                data-testid={tid('field-counterAccountCode')}
              >
                <label className={styles.label}>{labels.lineThAccount} *</label>
                <AccountSearchInput
                  api={erpFinanceAccountSearchApi}
                  className={searchFieldClass}
                  value={counterAccountCode}
                  primaryDisplay={formatAccountDisplay(counterAccountCode, counterAccountName)}
                  onChange={a => {
                    setCounterAccountCode(a.code);
                    setCounterAccountName(a.name);
                  }}
                  onClear={() => {
                    setCounterAccountCode('');
                    setCounterAccountName('');
                  }}
                  showLabel={false}
                  showSecondaryInput={false}
                  placeholder={ph('TK đối ứng...')}
                  disabled={searchDisabled}
                />
              </div>
            )}
            {!showCounterAccountHeader && (
              <div
                id={tid('field-description')}
                className={`${styles.field} ${styles.spanCol3}`}
                data-testid={tid('field-description')}
              >
                <label className={styles.label}>{labels.description}</label>
                <VoucherDescriptionField
                  data-testid={tid('field-description-input')}
                  value={description}
                  error={fieldErrors.description}
                  placeholder={ph('Nhập diễn giải...')}
                  className={textareaClassName}
                  onChange={v => {
                    setDescription(v);
                    patchHeaderFieldError('description', v);
                  }}
                  readOnly={textareaReadOnly}
                  disabled={textareaDisabled}
                />
              </div>
            )}
          </div>

          {showCounterAccountHeader && (
            <div className={styles.row4}>
              <div
                id={tid('field-description')}
                className={`${styles.field} ${styles.spanCol4}`}
                data-testid={tid('field-description')}
              >
                <label className={styles.label}>{labels.description}</label>
                <VoucherDescriptionField
                  data-testid={tid('field-description-input')}
                  value={description}
                  error={fieldErrors.description}
                  placeholder={ph('Nhập diễn giải...')}
                  className={textareaClassName}
                  onChange={v => {
                    setDescription(v);
                    patchHeaderFieldError('description', v);
                  }}
                  readOnly={textareaReadOnly}
                  disabled={textareaDisabled}
                />
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
};
